<script>
    /* === FIX 2: GLOBAL COMMAND EXECUTOR === */
    /* 使用唯一函数名，避免与SillyTavern的triggerSlash冲突 */
    function _execCmd(cmd) {
        // 优先使用SillyTavern的原生函数
        if (typeof window.triggerSlash === 'function') {
            window.triggerSlash(cmd);
        } else {
            // 回退到alert弹窗，确保用户能看到指令
            console.log("CMD:", cmd);
            alert("Chỉ lệnh đã gửi:\n" + cmd);
        }
    }
    /* === GLOBAL: PAGE NAVIGATION === */
    function _navTo(pageId) {
        // 1. Journal Panic Reset - 离开日记页时重置里模式
        const journal = document.getElementById('view-journal');
        if (journal.classList.contains('panic-mode')) {
            journal.classList.remove('panic-mode');
            document.getElementById('debug-text').innerText = "Quét sâu";
            document.getElementById('debug-icon').className = "fa-solid fa-fingerprint";
        }
        // 2. View Switching
        document.querySelectorAll('.page-view').forEach(p => p.classList.remove('active'));
        document.getElementById('view-' + pageId).classList.add('active');
    }
    /* === 1. LAUNCH LOGIC === */
    document.addEventListener('DOMContentLoaded', () => { setTimeout(startLaunch, 500); });
    function startLaunch() {
        const steps = [
            { pct: 15, msg: "Establishing Bio-Link..." },
            { pct: 30, msg: "Scanning Subject A..." },
            { pct: 45, msg: "Scanning Subject B..." },
            { pct: 60, msg: "Handshake Protocol..." },
            { pct: 75, msg: "Syncing Pain Receptors..." },
            { pct: 90, msg: "Elevating Privileges..." },
            { pct: 100, msg: "System Ready." }
        ];
        const bar = document.getElementById('p-bar');
        const txt = document.getElementById('s-text');
        const launchView = document.getElementById('view-launch');
        const controlView = document.getElementById('view-control');
        let stepIndex = 0;
        const interval = setInterval(() => {
            if (stepIndex >= steps.length) {
                clearInterval(interval);
                setTimeout(() => {
                    launchView.classList.add('finished');
                    controlView.classList.add('active');
                }, 400); return;
            }
            bar.style.width = steps[stepIndex].pct + "%";
            txt.innerText = steps[stepIndex].msg;
            stepIndex++;
        }, 300);
    }
    /* === 2. JOURNAL LOGIC === */
    document.getElementById('debug-trigger').addEventListener('click', () => {
        const v = document.getElementById('view-journal');
        const overlay = v.querySelector('#glitch-overlay');
        overlay.style.animation = 'none'; void overlay.offsetWidth;
        overlay.style.animation = 'glitch-flash 0.4s steps(5) forwards';
        const isPanic = v.classList.toggle('panic-mode');
        document.getElementById('debug-text').innerText = isPanic ? "Thoát debug" : "Quét sâu";
        document.getElementById('debug-icon').className = isPanic ? "fa-solid fa-power-off" : "fa-solid fa-fingerprint";
    });
    document.getElementById('wrapper-a').addEventListener('click', () => triggerLog('A'));
    document.getElementById('wrapper-b').addEventListener('click', () => triggerLog('B'));
    function triggerLog(type) {
        const jV = document.getElementById('view-journal');
        const isPanic = jV.classList.contains('panic-mode');
        let cmd, msg;
        if (!isPanic) {
            cmd = `Xem Sổ tay ngọt ngào mẫu ${type}`;
            msg = type === 'A' ? "⸝⸝⸝ ╸▵╺⸝⸝⸝Đang trộm xem sổ tay của mèo con..." : "૮  ˘͈ ᵕ˘͈ აĐang lật xem nhật ký tuần tra...";
        } else {
            cmd = `Xem Nhật ký bí mật mẫu ${type}`;
            msg = type === 'A' ? "Đang chuyển bộ nhớ cốt lõi DUMP_A..." : "Đang cưỡng chế ghi đè quyền chỉ đọc ROOT_B...";
        }
        _execCmd(`/echo ${msg} | /send ${cmd} | /trigger`);
    }
    /* === 3. ORACLE LOGIC === */
