    const field = document.getElementById('star-field');
    for(let i=0; i<60; i++) { const s = document.createElement('div'); s.className = 'star'; s.style.width = Math.random()*1.5 + 'px'; s.style.height = s.style.width; s.style.left = Math.random()*100 + '%'; s.style.top = Math.random()*100 + '%'; s.style.setProperty('--dur', (Math.random()*4+3)+'s'); s.style.setProperty('--op', (Math.random()*0.4+0.2)); field.appendChild(s); }
