    }
    function closeCard() { document.getElementById('reveal-overlay').classList.remove('active'); }
    function confirmFate() { if(!activeFate) return; _execCmd(`/echo severity=info Vận mệnh đã neo: ${activeFate.cn} | /send [Chỉ lệnh hệ thống] Vui lòng lấy "${activeFate.cn}" làm cảm hứng cốt lõi hoặc chủ đề, viết tiếp cốt truyện hiện tại một cách tự nhiên. | /trigger`); closeCard(); }
    /* === 4. CONTROL LOGIC === */
    let stagingPool = {}; let customCmdTarget = 'G';
    function setCmdTarget(t, el) { customCmdTarget = t; document.querySelectorAll('.chan-btn').forEach(b => b.classList.remove('active')); el.classList.add('active'); }
    function addCustomCmd() { const input = document.getElementById('custom-input'); const text = input.value.trim(); if(!text) return; stagingPool[`cust_${Date.now()}`] = { tag: customCmdTarget, desc: `"${text}"`, cmd: text }; input.value = ''; updateIsland(); }
    function updateRange(key, val, type, name) { document.getElementById('val-'+key).innerText = val; if(key === 'global_sync') document.getElementById('sync-fill').style.width = val + '%'; else document.getElementById(type === 'A' ? 'pain-fill-a' : 'pain-fill-b').style.width = (val/2) + '%'; stagingPool[key] = { tag: type || 'G', desc: `${name}: ${val}%`, cmd: `Điều chỉnh ${name} thành ${val}%` }; updateIsland(); }
    function toggleBtn(type, func, val, name, el) { let siblings = document.getElementById(`grp-${type}-${func}`).children; for(let sib of siblings) sib.classList.remove('selected'); el.classList.add('selected'); stagingPool[`${type}_${func}`] = { tag: type, desc: `${func.toUpperCase()}: ${val.toUpperCase()}`, cmd: `Chuyển ${func === 'voice' ? 'chế độ giọng nói' : 'trạng thái nguồn điện'} sang [${name}]` }; updateIsland(); }
    function updateIsland() { const count = Object.keys(stagingPool).length; document.getElementById('staged-count').innerText = count; document.getElementById('staging-island').classList.toggle('visible', count > 0); if(count === 0) document.getElementById('cmd-sheet').classList.remove('open'); renderSheet(); }
    function renderSheet() { const container = document.getElementById('cmd-sheet'); container.innerHTML = ''; for(let key in stagingPool) { let item = stagingPool[key]; let tagClass = item.tag === 'A' ? 'tag-A' : (item.tag === 'B' ? 'tag-B' : 'tag-G'); let div = document.createElement('div'); div.className = 'sheet-item'; div.innerHTML = `<div style="display:flex; align-items:center; overflow:hidden;"><span class="sheet-tag ${tagClass}">${item.tag === 'G' ? 'GLOBAL' : 'UNIT-'+item.tag}</span><span class="sheet-text">${item.desc}</span></div><i class="fa-solid fa-xmark sheet-del" onclick="deleteItem('${key}')"></i>`; container.appendChild(div); } }
    function deleteItem(key) { delete stagingPool[key]; updateIsland(); }
    function clearStaging() { stagingPool = {}; updateIsland(); }
    function toggleSheet() { document.getElementById('cmd-sheet').classList.toggle('open'); }
    function switchTab(type, btn) { document.querySelectorAll('.tab-opt').forEach(b => b.classList.remove('active-a', 'active-b')); btn.classList.add(type==='A'?'active-a':'active-b'); document.querySelectorAll('.c-tab-content').forEach(c => c.classList.remove('active')); document.getElementById('panel-'+type).classList.add('active'); }
    function pushCommands() { let keys = Object.keys(stagingPool); if(keys.length === 0) return; let finalPrompt = "[Chỉ lệnh DollPhone] {{user}} đã điều chỉnh chuỗi tín hiệu kiểm soát thần kinh, vui lòng thực thi:\n"; let groups = { G: [], A: [], B: [] }; keys.forEach(k => groups[stagingPool[k].tag].push(stagingPool[k].cmd)); if(groups.G.length > 0) finalPrompt += `\n【Chỉ lệnh Toàn cục/Cưỡng chế】\n- ${groups.G.join('\n- ')}`; if(groups.A.length > 0) finalPrompt += `\n\n【Chỉ lệnh Cá thể A (GT-X02A)】\n- ${groups.A.join('\n- ')}`; if(groups.B.length > 0) finalPrompt += `\n\n【Chỉ lệnh Cá thể B (GT-X02B)】\n- ${groups.B.join('\n- ')}`; _execCmd(`/echo severity=success Chuỗi chỉ lệnh đã tải lên (${keys.length}) | /send ${finalPrompt} | /trigger`); clearStaging(); }
    /* === 5. MEMORY LOGIC === */
    let mCur = { sub: 'A', mode: 'ghost' };
