        <header class="fixed-header"><div class="search-container"><input type="text" id="search-input" class="glass-input" placeholder="Tìm kiếm: phương án cải tạo, hệ thống cộng cảm..."><button class="search-btn" onclick="runSearch()"><i class="fa-solid fa-magnifying-glass"></i></button></div></header>
        <div class="scroll-view">
