            <div class="topic-category-title-v2 store-title-bar" style="margin-top:30px;"><div style="display:flex; align-items:center; gap:8px;"><i class="fa-solid fa-store store-icon-title"></i> Gợi ý đồ tốt</div><button class="btn-all-in" onclick="orderAllItems()">Gói mang về</button></div>
