      <div class="fixed-header-post"><div class="post-header-btn btn-cancel" onclick="hideNewPostPage()">Hủy</div><div class="post-header-btn btn-post" onclick="submitPost()">Đăng</div></div>
      <i class="fa-solid fa-feather-pointed deco-sticker sticker-feather"></i>
      <div class="scroll-view" style="padding-top:20px;">
        <div class="post-form-card" style="margin-top:70px;"><input type="text" id="post-title-input" placeholder="Nhập một tiêu đề thú vị..."><textarea id="post-content-textarea" placeholder="Chia sẻ tâm đắc nuôi dưỡng, ghi chép cải tạo hoặc bất cứ chuyện thú vị nào..."></textarea><div id="image-preview-container"></div><div id="tag-container"></div><div class="actions-bar"><button class="action-button" onclick="addImage()"><i class="fa-solid fa-camera-retro"></i></button><button class="action-button" id="tag-toggle-btn" onclick="toggleTagDrawer()"><i class="fa-solid fa-tag"></i></button></div><div class="tag-drawer" id="tag-drawer"><input type="text" id="tag-input" placeholder="Thêm thẻ, nhấn Enter xác nhận..." onkeydown="if(event.key === 'Enter') addTagFromInput()"><button class="add-btn" onclick="addTagFromInput()">Thêm</button></div></div>
      </div>
