</div>
<script>
    // Raw data placeholder from regex
    const rawData = `$1`;
    /* === DATA PARSER (THE BRAIN) === */
    const Parser = {
        parse: function(text) {
            const result = { carousel: [], posts: [], store: [] };
            try {
                // Welcome Message
                const welcomeMatch = text.match(/\[Welcome\|(.*?)\]/);
                if (welcomeMatch) result.welcome = welcomeMatch[1];
                // Carousel
                const carMatch = text.match(/\[Carousel\|(.*?)\|(.*?)\|(.*?)\|(.*?)\|(.*?)\|(.*?)\]/);
                if (carMatch) {
                    result.carousel.push({ title: carMatch[1], desc: carMatch[2], tag: carMatch[3] });
                    result.carousel.push({ title: carMatch[4], desc: carMatch[5], tag: carMatch[6] });
                }
                // Hot Posts
                const postsMatch = text.match(/\[Posts\]([\s\S]*?)\[\/Posts\]/);
                if (postsMatch) {
                    const postItems = postsMatch[1].match(/\{Post\|(.*?)\|(.*?)\|(.*?)\|(.*?)\}/g);
                    if (postItems) {
                        result.posts = postItems.map(item => {
                            const fields = item.replace('{Post|', '').replace('}', '').split('|');
                            return { title: fields[0], tag: fields[1], heat: fields[2], snippet: fields[3] };
                        });
                    }
                }
                // Store Items
                const storeMatch = text.match(/\[Store\|(.*?)\|(.*?)\|(.*?)\|(.*?)\]/);
                 if (storeMatch) {
                    result.store.push({ icon: storeMatch[1], title: storeMatch[2] });
                    result.store.push({ icon: storeMatch[3], title: storeMatch[4] });
                }
            } catch (e) {
                console.error("Fatal parsing error:", e);
                return { error: "Failed to parse data." };
            }
            return result;
        },
        render: function(data) {
            if (data.error) { document.body.innerHTML = `<h1>Kết xuất thất bại</h1><p>Lỗi phân tích dữ liệu: ${data.error}</p>`; return; }
            // Welcome Text
            if (data.welcome) document.getElementById('welcome-text').innerText = data.welcome;
            // Carousel
            const carouselContainer = document.getElementById('home-carousel-view');
            carouselContainer.innerHTML = '';
            if (data.carousel) {
                data.carousel.forEach(item => {
                    const tagColor = item.tag === 'Sản phẩm mới về' ? 'tag-blue' : 'tag-purple';
                    carouselContainer.innerHTML += `
                        <div class="hero-card" onclick="openPost('${item.title.replace(/'/g, "\\'")}', '${item.desc.replace(/'/g, "\\'")}')">
                            <span class="sub-tag ${tagColor}">${item.tag}</span>
                            <div class="h-title">${item.title}</div>
                            <div class="h-desc">${item.desc}</div>
                        </div>`;
                });
            }
            // Hot Posts
            const postsContainer = document.getElementById('home-posts-list');
            postsContainer.innerHTML = '';
            if(data.posts) {
                data.posts.forEach(post => {
                    postsContainer.innerHTML += `
                        <div class="post-card" onclick="openPost('${post.title.replace(/'/g, "\\'")}', '${post.snippet.replace(/'/g, "\\'")}')">
                            <div class="post-title">${post.title}</div>
                            <div class="post-snippet">${post.snippet}</div>
                            <div class="post-footer">
                                <div class="post-meta-tag"><span class="dot" style="background:var(--accent-pink);"></span> ${post.tag}</div>
                                <div class="post-stats"><i class="fa-solid fa-arrow-trend-up"></i> ${post.heat}</div>
                            </div>
                        </div>`;
                });
            }
            // Store Items
            const storeContainer = document.getElementById('home-store-list');
            storeContainer.innerHTML = '';
            if(data.store) {
                data.store.forEach(item => {
                    storeContainer.innerHTML += `
                        <div class="store-card" data-title="${item.title.replace(/"/g, '&quot;')}">
                            <div class="store-image"><i class="${item.icon}"></i></div>
                            <div class="store-title">${item.title}</div>
                            <button class="btn-order-item" onclick="orderItem(this)">Đặt hàng</button>
                        </div>`;
                });
            }
        }
    };
    /* === INITIALIZATION & INTERACTION (Corrected from v1.4) === */
    function triggerCommand(commandText) { if (typeof triggerSlash === 'function') { triggerSlash(`/send ${commandText} | /trigger`); } else { console.log(`[Chỉ lệnh nguyên mẫu] ${commandText}`); } }
    function showToast(message) { if (typeof triggerSlash === 'function') { triggerSlash(`/echo severity=success ${message}`); } else { alert(message); } }
    document.addEventListener('DOMContentLoaded', function() {
        const loadingPage = document.getElementById('page-loading');
        const mainPage = document.getElementById('page-home');
        // Render data if available
        try {
            if(rawData && rawData.trim() !== '$'+'1' && rawData.trim() !== ''){
                const parsedData = Parser.parse(rawData);
                Parser.render(parsedData);
            }
        } catch (e) {
            console.error("Render Error on DOMContentLoaded", e);
        }
        // Loading animation
        setTimeout(() => {
            loadingPage.style.transition = 'opacity 0.6s ease-out';
            loadingPage.style.opacity = '0';
            mainPage.classList.add('active');
            setTimeout(() => { loadingPage.style.display = 'none'; }, 600);
        }, 4000);
    });
    const fab = document.getElementById('fab-post');
    const newPostPage = document.getElementById('page-new-post');
    function showNewPostPage() { newPostPage.classList.add('active'); fab.classList.add('hidden'); }
    function hideNewPostPage() { if (confirm('Bạn có chắc chắn muốn hủy chỉnh sửa không?')) { newPostPage.classList.remove('active'); fab.classList.remove('hidden'); } }

    let imageCounter = 0;
    function addImage() { const desc = prompt("Thêm mô tả cho hình ảnh này:"); if (desc && desc.trim() !== '') { imageCounter++; const container = document.getElementById('image-preview-container'); const cardId = `image-${imageCounter}`; const newCard = document.createElement('div'); newCard.className = 'image-placeholder-card'; newCard.id = cardId; newCard.innerHTML = `<div class="remove-item-btn" onclick="this.parentElement.remove()"><i class="fa-solid fa-xmark"></i></div><div class="placeholder-icon"><i class="fa-solid fa-paw"></i></div><div class="placeholder-desc">${desc.trim()}</div>`; container.appendChild(newCard); } }
    function toggleTagDrawer() { const drawer = document.getElementById('tag-drawer'); const button = document.getElementById('tag-toggle-btn'); const isActive = drawer.classList.toggle('active'); button.classList.toggle('active', isActive); if (isActive) document.getElementById('tag-input').focus(); }
    function addTagFromInput() { const input = document.getElementById('tag-input'); let tagText = input.value.trim().replace(/#/g, ''); if (tagText) { const container = document.getElementById('tag-container'); const newTag = document.createElement('div'); newTag.className = 'tag-pill'; newTag.innerHTML = `<span>#${tagText}</span><i class="fa-solid fa-xmark remove-tag-btn" onclick="this.parentElement.remove()"></i>`; container.appendChild(newTag); input.value = ''; input.focus(); } }
    function runSearch() { const keyword = document.getElementById('search-input').value.trim(); if (keyword) { triggerCommand(`{{user}} đã tìm kiếm trên diễn đàn: “${keyword}”, vui lòng hiển thị kết quả tìm kiếm liên quan.`); showToast(`Đang tìm kiếm “${keyword}”...`); } }
    function quickSearch(topic) { triggerCommand(`{{user}} đã nhấp vào chủ đề khám phá trên diễn đàn: “${topic}”, vui lòng hiển thị kết quả tìm kiếm liên quan.`); showToast(`Đang xem “${topic}”...`); }
    function openPost(title, summary) { const commandText = `{{user}} đã xem bài viết: “${title}”, tóm tắt: “${summary}”. Vui lòng hiển thị chi tiết bài viết dựa trên thông tin này.`; triggerCommand(commandText); }

    function submitPost() {
        const title = document.getElementById('post-title-input').value.trim();
        const content = document.getElementById('post-content-textarea').value.trim();
        if (!title && !content) { showToast("Tiêu đề và nội dung phải điền ít nhất một mục nhé."); return; }
        const images = Array.from(document.querySelectorAll('#page-new-post .placeholder-desc')).map(el => el.innerText);
        const tags = Array.from(document.querySelectorAll('#page-new-post .tag-pill span')).map(el => el.innerText);
        let command = `{{user}} đã đăng bài viết mới, vui lòng cho NPC bình luận tương tác. Nội dung bài viết như sau:\n[Tiêu đề]: ${title}\n[Nội dung]: ${content}`;
        if (images.length > 0) command += `\n[Mô tả ảnh]: (${images.join('), (')})`;
        if (tags.length > 0) command += `\n[Thẻ]: ${tags.join(', ')}`;
        triggerCommand(command);
        showToast('Bài viết đã được đăng thành công!');
        // [修正] 直接关闭页面，不再调用hideNewPostPage()
        newPostPage.classList.remove('active');
        fab.classList.remove('hidden');
    }
    function orderItem(button) { if(button.classList.contains('ordered')) return; const card = button.closest('.store-card'); const title = card.dataset.title; triggerCommand(`{{user}} đã đặt hàng và nhận được hàng hóa sau, vui lòng đẩy nhanh cốt truyện: - Hàng hóa: ${title}`); showToast(`${title} Đã thêm vào đơn hàng!`); button.classList.add('ordered'); button.innerText = '✓'; }
    function orderAllItems() {
        const itemCards = document.querySelectorAll('#home-store-list .store-card');
        let commandParts = ["{{user}} đã đặt hàng và nhận được hàng hóa sau, vui lòng đẩy nhanh cốt truyện:"];
        let orderedSomething = false;
        itemCards.forEach(card => {
            const orderButton = card.querySelector('.btn-order-item');
            if (!orderButton.classList.contains('ordered')) {
                const title = card.dataset.title;
                commandParts.push(`- Hàng hóa: ${title}`);
                orderButton.classList.add('ordered');
                orderButton.innerText = '✓';
                orderedSomething = true;
            }
        });
        if (orderedSomething) { triggerCommand(commandParts.join('\n')); showToast('Tất cả đồ tốt đều đã được đóng gói đặt hàng!'); }
        else { showToast('Tất cả gợi ý đồ tốt đều đã nằm trong đơn hàng rồi nha~'); }
    }
</script>
</body>
