    <script>
        const rawData = `$1`; // RegEx data grab
        /* === Thư viện hoảng loạn (Panic Library) === */
        const panicMessages = [
            { icon: "fa-solid fa-tower-broadcast", text: "Phát hiện dao động tín hiệu bất thường...", sub: "Signal Lost: 404_Unreachable", danger: true },
            { icon: "fa-solid fa-user-secret", text: "⚠️ Chủ diễn đàn nghi ngờ bị bắt<br>Đang tiêu hủy khóa tạm thời...", sub: "Executing Protocol: BURN_ALL", danger: true },
            { icon: "fa-solid fa-triangle-exclamation", text: "Đường truyền uplink bị ngắt<br>Đang tiêu hủy ổ cứng vật lý...", sub: "Drive Erased: 98%...", danger: true },
            { icon: "fa-solid fa-eye-slash", text: "Cảnh sát mạng đang quét băng tần này<br>Toàn viên giữ im lặng!", sub: "Status: SILENT_MODE", danger: true },
            { icon: "fa-solid fa-network-wired", text: "Hệ thống tản nhiệt máy chủ hỏng<br>Phòng máy hơi nóng...", sub: "Temp: 98°C - MELTDOWN", danger: false }, // Thỉnh thoảng có cái bình thường
            { icon: "fa-solid fa-bug", text: "Một con gián thật chui vào máy chủ<br>Đang cố bắt nó...", sub: "Bug Type: Blatta orientalis", danger: false },
            { icon: "fa-solid fa-ban", text: "Cảnh báo bẫy honeypot<br>Nút mạng này đã bị đánh dấu, ngắt kết nối ngay!", sub: "Trace Detected: IP_LOGGED", danger: true }
        ];
        /* === Trình phân tích thông minh (The Brain) === */
        const Parser = {
            parse: function(text) {
                const result = { keyword: "", list: [] };
                try {
                    const kwMatch = text.match(/\[Keyword\|(.*?)\]/);
                    if(kwMatch) result.keyword = kwMatch[1];
                    const listBlock = text.match(/\[Results\]([\s\S]*?)\[\/Results\]/);
                    if(listBlock) {
                        const items = listBlock[1].match(/\{Res\|(.*?)\|(.*?)\|(.*?)\|(.*?)\|(.*?)\|(.*?)\}/g);
                        if(items) {
                            result.list = items.map(item => {
                                const f = item.replace('{Res|','').replace('}','').split('|');
                                return { title: f[0], snip: f[1], icon: f[2], theme: f[3], user: f[4], heat: f[5] };
                            });
                        }
                    }
                } catch(e) { console.error("Parse Error"); return null; } // Trả về null để kích hoạt panic
                return result;
            },
            render: function(data) {
                const container = document.getElementById('results-list-container');
                container.innerHTML = '';
                // Nếu không có dữ liệu hoặc phân tích thất bại, vào chế độ hoảng loạn
                if(!data || !data.list || data.list.length === 0) {
                    Parser.renderPanic(container);
                    return;
                }
                if(data.keyword) document.getElementById('header-search-input').value = data.keyword;
                data.list.forEach(item => {
                    const card = document.createElement('div');
                    card.className = 'result-card';
                    card.onclick = function() { openPost(item.title, item.snip); };
                    const themeClass = `theme-${item.theme || 'blue'}`;
                    card.innerHTML = `
                        <div class="result-thumbnail ${themeClass}"><i class="${item.icon}"></i></div>
                        <div class="result-content">
                            <h4 class="result-title">${item.title}</h4>
                            <p class="result-snippet">${item.snip}</p>
                            <div class="result-meta">
                                <div class="meta-user"><i class="fa-solid fa-user-circle"></i><span>${item.user}</span></div>
                                <div class="meta-stats"><i class="fa-solid fa-fire"></i><span>${item.heat}</span></div>
                            </div>
                        </div>
                    `;
                    container.appendChild(card);
                });
                document.getElementById('end-marker').style.display = 'flex';
                if(data.keyword) applyHighlight(data.keyword);
            },
            renderPanic: function(container) {
                // Ngẫu nhiên chọn một tin xấu
                const panic = panicMessages[Math.floor(Math.random() * panicMessages.length)];
                const dangerClass = panic.danger ? 'danger' : '';
                container.innerHTML = `
                    <div class="panic-container">
                        <div class="panic-icon ${dangerClass}"><i class="${panic.icon}"></i></div>
                        <div class="panic-text">${panic.text}</div>
                        <div class="panic-glitch-text">> ${panic.sub} _</div>
                    </div>
                `;
                document.getElementById('end-marker').style.display = 'none';
            }
        };
        /* === Logic bút đánh dấu (Highlighter) === */
        function applyHighlight(keyword) {
            const rainbowColors = [ 'rgba(255, 154, 162, 0.5)', 'rgba(128, 222, 234, 0.5)', 'rgba(140, 215, 144, 0.5)', 'rgba(255, 183, 77, 0.5)', 'rgba(179, 157, 219, 0.5)' ];
            let colorIndex = 0;
            const cards = document.querySelectorAll('.result-card');
            cards.forEach(card => {
                const highlight = (el) => {
                    const regex = new RegExp(`(${keyword})`, 'gi');
                    el.innerHTML = el.innerHTML.replace(regex, (match) => {
                        const color = rainbowColors[colorIndex % rainbowColors.length];
                        colorIndex++;
                        return `<span class="highlighted-keyword" style="--highlight-color: ${color}">${match}</span>`;
                    });
                };
                const tEl = card.querySelector('.result-title');
                const sEl = card.querySelector('.result-snippet');
                if(tEl) highlight(tEl);
                if(sEl) highlight(sEl);
            });
        }
        /* === Logic tương tác === */
        function triggerCommand(cmd) { if(typeof triggerSlash === 'function') triggerSlash(`/send ${cmd} | /trigger`); else console.log(cmd); }
        function goHome() { triggerCommand("Quay về trang chủ diễn đàn"); }
        function doSearch() {
            const val = document.getElementById('header-search-input').value.trim();
            if(val) triggerCommand(`{{user}} đã tìm kiếm: ${val}`);
        }
        function openPost(title, snip) {
            const cTitle = title.replace(/'/g, "\\'");
            const cSnip = snip.replace(/'/g, "\\'");
            triggerCommand(`{{user}} đã nhấp xem bài viết:\nTiêu đề: ${cTitle}\nTóm tắt: ${cSnip}\nVui lòng tạo nội dung chi tiết bài viết.`);
        }
        /* === Khởi tạo === */
        document.addEventListener('DOMContentLoaded', () => {
            // Nếu rawData là placeholder chưa thay thế (AI không xuất nội dung), hoặc rỗng -> Kích hoạt Panic
            if(!rawData || rawData.trim() === '$'+'1' || rawData.trim() === '') {
                Parser.renderPanic(document.getElementById('results-list-container'));
            } else {
                const data = Parser.parse(rawData);
                // Nếu kết quả phân tích lỗi, hàm render bên trong cũng sẽ kích hoạt Panic
                Parser.render(data);
            }
        });
    </script>
</div>
</body>
