<script>
    // Raw data placeholder
    const rawData = `$1`;
    /* === DATA PARSER (THE BRAIN) v6.2 - FLAWLESS EDITION === */
    const Parser = {
        parse: function(text) {
            const result = { images: [], tags: [], comments: [] };
            try {
                // Meta
                const metaMatch = text.match(/\[Meta\|(.*?)\|(.*?)\|(.*?)\|(.*?)\|(.*?)\]/);
                if (metaMatch) {
                    result.title = metaMatch[1]; result.user = metaMatch[2];
                    result.time = metaMatch[3];  result.like = metaMatch[4]; result.dislike = metaMatch[5];
                }
                // Content, Images, Tags (unchanged)
                const contentMatch = text.match(/\[Content\|([\s\S]*?)\]/);
                if (contentMatch) result.content = contentMatch[1];
                const imgMatch = text.match(/\[Images\|(.*?)\]/);
                if (imgMatch && imgMatch[1] && imgMatch[1].trim()) result.images = imgMatch[1].split('|').map(s => s.trim()).filter(s => s);
                const tagMatch = text.match(/\[Tags\|(.*?)\]/);
                if (tagMatch && tagMatch[1] && tagMatch[1].trim()) result.tags = tagMatch[1].split('|').map(s => s.trim()).filter(s => s);
                // Comments (Bugfixed and more robust)
                const lines = text.split('\n');
                let currentComment = null;
                lines.forEach(line => {
                    line = line.trim();
                    if (!line) return;
                    // Bugfix: Regex handles 3 or 4 parameters correctly
                    const cm = line.match(/^\[C\|([^|]*)\|([^|]*)\|([^|]*?)(?:\|([^|]*))?\]$/);
                    if (cm) {
                        currentComment = { user: cm[1], time: cm[2], text: cm[3], image: (cm[4] || '').trim(), subs: [] };
                        result.comments.push(currentComment);
                        return;
                    }
                    const sm = line.match(/^\[S\|([^|]*)\|([^|]*)\|([^|]*)\]$/);
                    if (sm && currentComment) {
                        currentComment.subs.push({ user: sm[1], to: sm[2], text: sm[3] });
                        return;
                    }
                });
            } catch (e) {
                console.error("Fatal parsing error:", e);
                return { error: "Failed to parse data." };
            }
            return result;
        },
        render: function(data) {
            // Render logic is identical to v6.1
            if (data.error) {
                document.getElementById('post-title').innerText = "Phân tích dữ liệu thất bại";
                document.getElementById('post-content').innerText = "AI có thể đã xuất định dạng sai, vui lòng kiểm tra hoặc thử lại.\nLỗi: " + data.error;
                return;
            }
            if(data.title) document.getElementById('post-title').innerText = data.title;
            if(data.user) document.getElementById('post-user').innerText = data.user;
            if(data.time) document.getElementById('post-time').innerText = data.time;
            if(data.content) document.getElementById('post-content').innerText = data.content;
            if(data.like) document.getElementById('post-like').innerText = data.like;
            if(data.dislike) document.getElementById('post-dislike').innerText = data.dislike;
            const imgGrid = document.getElementById('post-images-grid');
            imgGrid.innerHTML = '';
            if(data.images && data.images.length > 0) { data.images.forEach(desc => { const card = document.createElement('div'); card.className = 'image-flip-card'; card.onclick = function() {this.classList.toggle('flipped');}; card.innerHTML = `<div class="image-flip-card-inner"><div class="image-flip-card-front"><i class="fa-solid fa-paw"></i></div><div class="image-flip-card-back">${desc}</div></div>`; imgGrid.appendChild(card); }); }
            const tagCont = document.getElementById('post-tags');
            tagCont.innerHTML = '';
            if(data.tags) { data.tags.forEach(tag => { const pill = document.createElement('span'); pill.className = 'tag-pill'; pill.innerText = tag.startsWith('#') ? tag : '#'+tag; pill.onclick = function() { onTagClick(tag); }; tagCont.appendChild(pill); }); }
            const commList = document.getElementById('comments-list');
            commList.innerHTML = '';
            if(data.comments) {
                data.comments.forEach(c => {
                    const card = document.createElement('div'); card.className = 'comment-thread-card';
                    let subsHtml = '';
                    if(c.subs.length > 0) { subsHtml = `<div class="sub-reply-container">${c.subs.map(s => `<div class="sub-reply-item"><span class="sub-user">${s.user}</span><span class="sub-reply-to">trả lời ${s.to}:</span><span class="sub-content">${s.text}</span><div class="sub-action-row"><i class="fa-solid fa-reply sub-reply-icon" onclick="openReplyComposeModal({targetUser: '${s.user.replace(/'/g,"\\'")}', targetContent: '${s.text.replace(/'/g,"\\'")}', isMainPostReply: false})"></i></div></div>`).join('')}</div>`; }
                    let commImgHtml = '';
                    if(c.image) { commImgHtml = `<div class="comment-images-list"><button class="comment-view-image-btn" onclick="showImageViewer('${c.image.replace(/'/g,"\\'")}')"><i class="fa-solid fa-paw"></i> Xem hình ảnh </button></div>`; }
                    card.innerHTML = `<div class="l1-header"><span class="l1-user">${c.user}</span><span class="l1-time">${c.time}</span></div><div class="l1-content">${c.text}</div>${commImgHtml}<div class="l1-actions"><button class="l1-reply-btn" onclick="openReplyComposeModal({targetUser: '${c.user.replace(/'/g,"\\'")}', targetContent: '${c.text.replace(/'/g,"\\'")}', isMainPostReply: false})"><i class="fa-solid fa-reply"></i> Trả lời</button></div>${subsHtml}`;
                    commList.appendChild(card);
                });
            }
        }
    };
    /* === INTERACTION FUNCTIONS (FINAL) === */
    document.addEventListener('DOMContentLoaded', () => { try { if(rawData && rawData.trim() && rawData.trim() !== '$'+'1') { const parsedData = Parser.parse(rawData); Parser.render(parsedData); } } catch(e) { console.error("Parse Error", e); document.body.innerHTML = `<h1>Kết xuất thất bại</h1><p>Đã xảy ra lỗi nghiêm trọng khi phân tích dữ liệu AI, vui lòng kiểm tra bảng điều khiển console.</p><pre>${e.stack}</pre>`;} const sv = document.getElementById('main-scroll-view'); const tb = document.getElementById('floating-toolbar'); const searchPop = document.getElementById('mini-search-popover'); if (sv && tb) { sv.addEventListener('scroll', () => { if (sv.scrollTop > 300) tb.classList.add('visible'); else { tb.classList.remove('visible'); searchPop.classList.remove('active'); } }); } });
    function triggerCommand(cmd) { if(typeof triggerSlash === 'function') triggerSlash(`/send ${cmd} | /trigger`); else console.log(`[CMD] ${cmd}`); }
    // BUGFIX 2: Command Enrichment
    function onTagClick(tagText) { triggerCommand(`{{user}} đã nhấp vào thẻ "${tagText}", vui lòng hiển thị kết quả tìm kiếm.`); }
    function runMiniSearch() { const v = document.getElementById('mini-search-val').value; if(v) { triggerCommand(`{{user}} đã tìm kiếm từ khóa "${v}", vui lòng hiển thị kết quả tìm kiếm.`); toggleMiniSearch(); } }
    // All other interaction functions remain the same
    function toggleMiniSearch() { document.getElementById('mini-search-popover').classList.toggle('active'); document.getElementById('mini-search-val').focus(); }
    function hideImageViewer() { document.getElementById('image-viewer-modal-overlay').classList.remove('active'); }
    function scrollToTop() { document.getElementById('main-scroll-view').scrollTo({ top: 0, behavior: 'smooth' }); }
    function showImageViewer(d) { document.getElementById('image-viewer-description').innerText = d; document.getElementById('image-viewer-modal-overlay').classList.add('active'); }
    function toggleLike(btn) { const s = btn.querySelector('.count'); let c = parseInt(s.innerText); if(btn.classList.contains('liked')) { btn.classList.remove('liked'); c--; } else { btn.classList.add('liked'); c++; } s.innerText = c; }
    function toggleDislike(btn) { const s = btn.querySelector('.count'); let c = parseInt(s.innerText); if(btn.classList.contains('disliked')) { btn.classList.remove('disliked'); c--; } else { btn.classList.add('disliked'); c++; } s.innerText = c; }
    let replyCtx = null; let replyImages = [];
    function openReplyMain() { const user = document.getElementById('post-user').innerText; const txt = document.getElementById('post-content').innerText; openReplyComposeModal({targetUser: 'Bài viết chính', targetContent: txt.substring(0,30)+'...', isMainPostReply: true}); }
    function openReplyComposeModal(opts) {
        replyCtx = opts;
        document.getElementById('modal-reply-target-user-display').innerText = opts.targetUser;
        document.getElementById('modal-reply-target-content-display').innerText = opts.targetContent;
        document.getElementById('modal-reply-textarea').value = '';
        document.getElementById('modal-image-preview-container').innerHTML = ''; replyImages = [];
        const imgBtn = document.getElementById('modal-img-add-button');
        // BUGFIX 1: Reply Image Permission Logic
        if (opts.isMainPostReply) {
            imgBtn.classList.remove('disabled');
        } else {
            imgBtn.classList.add('disabled');
        }
        document.getElementById('reply-modal-overlay').classList.add('active');
