    function hideReplyComposeModal() { document.getElementById('reply-modal-overlay').classList.remove('active'); }
    function modalAddImage() {
        if(document.getElementById('modal-img-add-button').classList.contains('disabled')) {
            alert('Trả lời trong chủ đề không thể đính kèm ảnh.'); return;
        }
        if(replyImages.length >= 1) { alert('Mỗi lần trả lời chỉ có thể đính kèm tối đa một ảnh.'); return; }
        const desc = prompt("Nhập mô tả ảnh:");
        if(desc) { replyImages.push(desc); const d = document.createElement('div'); d.className = 'modal-img-tag'; d.innerHTML = `<i class="fa-solid fa-paw"></i> ${desc.substring(0,8)}...`; document.getElementById('modal-image-preview-container').appendChild(d); }
    }
    function sendReplyFromModal() { const val = document.getElementById('modal-reply-textarea').value; if(!val && replyImages.length===0) return; let snippet = replyCtx.targetContent.length > 15 ? replyCtx.targetContent.substring(0,15)+"..." : replyCtx.targetContent; let cmd = replyCtx.isMainPostReply ? `Trả lời bài viết: Bình luận bài viết chính “${snippet}”: ${val}` : `Trả lời bài viết: Trả lời ${replyCtx.targetUser} “${snippet}”: ${val}`; if(replyImages.length > 0 && replyCtx.isMainPostReply) cmd += ` [Ảnh đính kèm: ${replyImages.join('; ')}]`; triggerCommand(cmd); hideReplyComposeModal(); }
</script>
