    // Sử dụng IIFE (Biểu thức hàm gọi ngay) để tránh ô nhiễm biến toàn cục
    (function() {
        // --- 1. Bộ phân tích tháng ---
        function getMonthAbbr(monthNumber) {
            const months = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC'];
            const index = parseInt(monthNumber, 10) - 1;
            return (index >= 0 && index < 12) ? months[index] + '.' : 'ERR.';
        }
        // --- 2. Hàm render chính ---
        function renderJournal() {
            // Lấy dữ liệu gốc từ các container ẩn một cách an toàn
            const dateEl = document.getElementById('raw-data-date');
            const titleEl = document.getElementById('raw-data-title');
            const bodyEl = document.getElementById('raw-data-body');
            // Nếu thiếu bất kỳ container dữ liệu nào thì dừng thực thi
            if (!dateEl || !titleEl || !bodyEl) return;
            const dateStr = dateEl.innerText;
            const title = titleEl.innerText;
            const body = bodyEl.innerText;
            // Kiểm tra định dạng chuỗi ngày tháng có hợp lệ không
            if (!/^\d{2}\.\d{2}$/.test(dateStr)) return;
            const [month, day] = dateStr.split('.');
            // Render ngày tháng và tiêu đề
            document.getElementById('date-day-placeholder').textContent = day;
            document.getElementById('date-month-placeholder').textContent = getMonthAbbr(month);
            document.getElementById('title-placeholder').textContent = title;
            // Render nội dung chính
            const contentContainer = document.getElementById('content-body-placeholder');
            contentContainer.innerHTML = '';
            const paragraphs = body.split('\n').filter(p => p.trim() !== '');
            paragraphs.forEach((pText, index) => {
                const pElement = document.createElement('div');
                pElement.className = 'text-paragraph';
                // Chỉ áp dụng chữ cái đầu dòng lớn (drop-cap) cho đoạn đầu tiên
                if (index === 0) {
                    pElement.classList.add('drop-cap');
                }
                pElement.textContent = pText;
                contentContainer.appendChild(pElement);
            });
            // Render ghi chú tĩnh ở chân trang
            const footerNote = document.createElement('div');
            footerNote.className = 'footer-note';
            footerNote.innerHTML = `
                <div class="note-text">
                    System Optimized : EUPHORIA+ Filter applied<br>
                    Auto-Translation complete.
                </div>
            `;
            contentContainer.appendChild(footerNote);
        }
        // --- 3. Khởi chạy render ---
        // Đảm bảo script chỉ chạy sau khi DOM đã tải hoàn tất
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', renderJournal);
        } else {
            renderJournal();
        }
    })();
</script>
