        </div>

        <div class="shard-scroll" id="shard-container">
            <!-- 隐藏的原始文本 -->
            <div id="raw-content" style="display:none;">$3</div>
            <!-- JS将在这里生成带金缮线条的 fragment-block -->
        </div>
        <div class="nav-dock-panic">
            <div class="nav-icon active"><i class="fa-solid fa-file-code"></i></div>
            <div class="nav-icon"><i class="fa-solid fa-dice-d20"></i></div>
            <div class="nav-icon"><i class="fa-solid fa-screwdriver-wrench"></i></div>
            <div class="nav-icon"><i class="fa-solid fa-triangle-exclamation"></i></div>
            <div class="nav-icon"><i class="fa-solid fa-skull"></i></div>
        </div>
    </div>
</div>
<script>
    document.addEventListener("DOMContentLoaded", function() {
        // 读取隐藏的原始文本
        const rawEl = document.getElementById('raw-content');
        if (!rawEl) return;
        const rawText = rawEl.innerText;
        const container = document.getElementById('shard-container');
        // 按换行符切割，并过滤空行
        const paragraphs = rawText.split(/\n/).filter(line => line.trim() !== '');
        // 为每一段创建“金缮容器”
        paragraphs.forEach(line => {
            // 1. 创建外层容器 (负责画侧边的金线和点)
            const block = document.createElement('div');
            block.className = 'fragment-block';
            // 2. 创建内层文本 (负责文字排版)
            const text = document.createElement('div');
            text.className = 'text-dark';

            // 3. 处理高亮 (Kintsugi Highlight)
            // 简单逻辑：如果文本中包含引号内容，将其标金
            // 这里为了安全，仅做纯文本填充，高亮逻辑可按需扩展
            text.innerText = line;
            // 4. 组装
            block.appendChild(text);
            container.appendChild(block);
        });
        // 清理原始数据
        rawEl.remove();
    });
</script>
</body>
</html>
