                try {
                    // Gọi hàm trực tiếp để chuyển tin nhắn thứ 0 (lời mở đầu) trong lịch sử trò chuyện sang swipeId được chỉ định
                    await setChatMessages([{ message_id: 0, swipe_id: swipeId }]);
                } catch (e) {
                    console.error("Lỗi khi thực thi setChatMessages: ", e);
                    // Nếu có lỗi, có thể hiện một thông báo
                    if (typeof triggerSlash === 'function') {
                        triggerSlash(`/echo severity=error Chuyển đổi lời mở đầu thất bại, vui lòng kiểm tra thông tin console.`);
                    }
                }
            } else {
                console.error("Lỗi: Không tìm thấy hàm 'setChatMessages' của Tavern Assistant. Vui lòng đảm bảo plugin liên quan đã được kích hoạt.");
                if (typeof triggerSlash === 'function') {
                    triggerSlash(`/echo severity=error Lỗi: Không tìm thấy hàm “setChatMessages”. Vui lòng kiểm tra xem plugin Tavern Assistant đã được cài đặt và kích hoạt chưa.`);
                }
            }
        }
        // [Hàm chức năng hỗ trợ] Mở rộng/Thu gọn hướng dẫn phía dưới
        function toggleGuide() {
            document.getElementById('guide-content-panel').classList.toggle('expanded');
        }
        // Khi nhấp vào bên ngoài khu vực hướng dẫn, tự động thu gọn hướng dẫn
        document.body.addEventListener('click', function(event) {
            const guideArea = document.querySelector('.guide-area');
            if (!guideArea.contains(event.target)) {
                document.getElementById('guide-content-panel').classList.remove('expanded');
            }
        }, true);
    </script>
</body>
</html>
