        .custom-input { width: 100%; padding: 10px 15px; border: 2px solid var(--border-color); border-radius: 12px; background-color: #f7f9fa; font-size: 15px; margin-top: 10px; box-sizing: border-box; display: none; animation: fadeIn 0.3s; font-family: inherit; }
        #ordering-page { height: 100%; overflow: hidden; }
        .order-header { background: linear-gradient(to right, #ffffff, #fff8f0); padding: 15px 20px; text-align: center; border-bottom: 2px solid var(--border-color); flex-shrink: 0; z-index: 10; }
        .order-logo { font-size: 24px; font-weight: 800; color: var(--brand-primary); font-family: 'M PLUS Rounded 1c', sans-serif; }
        .order-logo .logo-icon { animation: wave 2.5s infinite; display: inline-block; transform-origin: 70% 70%; }
        @keyframes wave { 0% { transform: rotate(0deg); } 10% { transform: rotate(14deg); } 20% { transform: rotate(-8deg); } 30% { transform: rotate(14deg); } 40% { transform: rotate(-4deg); } 50% { transform: rotate(10deg); } 60% { transform: rotate(0deg); } 100% { transform: rotate(0deg); } }
        .order-subtitle { font-size: 14px; color: var(--text-secondary); margin-top: 5px; }
        .order-main { display: flex; flex-grow: 1; background-color: #f7f2ea; overflow: hidden; }
        .order-sidebar { width: 120px; background: var(--bg-panel); padding-top: 10px; overflow-y: auto; flex-shrink: 0; -webkit-overflow-scrolling: touch; }
        .order-category { padding: 15px 10px; cursor: pointer; font-weight: 700; color: var(--text-secondary); transition: all 0.2s ease; position: relative; text-align: center; }
        .order-category:hover { background-color: #fff8f0; color: var(--brand-primary); }
        .order-category.active { background-color: #f7f2ea; color: var(--brand-primary); }
        .order-category.active::before { content: ''; position: absolute; left: 0; top: 50%; transform: translateY(-50%); height: 60%; width: 5px; background-color: var(--brand-primary); border-radius: 0 5px 5px 0; }
        .order-content { flex-grow: 1; padding: 20px; overflow-y: auto; -webkit-overflow-scrolling: touch; }
        .content-section h3 { font-size: 18px; font-weight: 700; margin: 0 0 15px; padding-left: 10px; border-left: 4px solid var(--accent-green); color: var(--text-primary); }
        .item-card { background: white; border-radius: 15px; padding: 15px; margin-bottom: 15px; display: flex; align-items: center; box-shadow: 0 4px 12px rgba(224, 213, 201, 0.6); transition: transform 0.2s, box-shadow 0.2s; }
        .item-card:hover { transform: translateY(-3px); box-shadow: 0 6px 16px rgba(224, 213, 201, 0.8); }
        .item-info { flex-grow: 1; }
        .item-title { font-weight: 700; color: var(--text-primary); }
        .item-desc { font-size: 13px; color: var(--text-secondary); margin-top: 4px; }
        .add-to-cart-btn { background: var(--accent-pink); color: white; border: none; width: 36px; height: 36px; border-radius: 50%; font-size: 20px; font-weight: bold; cursor: pointer; transition: all 0.3s ease; flex-shrink: 0; margin-left: 15px; display: flex; justify-content: center; align-items: center; }
        .add-to-cart-btn:hover { transform: rotate(90deg) scale(1.1); }
        .add-to-cart-btn.added { background: var(--accent-green); transform: rotate(360deg); }
        .add-to-cart-btn.added::before { content: '✓'; }
        .order-footer { background: #fff; padding: 15px 20px; border-top: 1px solid var(--border-color); display: flex; justify-content: space-between; align-items: center; flex-shrink: 0; z-index: 10; box-shadow: 0 -5px 15px rgba(0,0,0,0.05); }
        .cart-info { display: flex; align-items: center; cursor: pointer; }
        .cart-icon { font-size: 28px; color: var(--brand-primary); position: relative; }
        .cart-icon-shake { animation: shake 0.5s; }
        @keyframes shake { 10%, 90% { transform: translate3d(-1px, 0, 0); } 20%, 80% { transform: translate3d(2px, 0, 0); } 30%, 50%, 70% { transform: translate3d(-4px, 0, 0); } 40%, 60% { transform: translate3d(4px, 0, 0); } }
        .cart-count { position: absolute; top: -5px; right: -8px; background: var(--accent-pink); color: white; width: 20px; height: 20px; border-radius: 50%; display: flex; justify-content: center; align-items: center; font-size: 12px; font-weight: 700; transform: scale(0); transition: transform 0.3s cubic-bezier(0.18, 0.89, 0.32, 1.28); }
        .cart-count.visible { transform: scale(1); }
        .cart-summary { margin-left: 10px; font-weight: 700; }
        .cart-summary-text { font-size: 16px; color: var(--text-primary); }
        .cart-summary-placeholder { color: var(--text-secondary); font-size: 14px; }
        .order-actions { display: flex; align-items: center; gap: 15px; }
        #add-remark-btn { color: var(--text-secondary); cursor: pointer; font-weight: 500; font-size: 14px; }
        #add-remark-btn:hover { color: var(--brand-primary); }
        .remark-section { background-color: var(--bg-main); padding: 15px 20px; display:none; }
        .remark-section textarea { width: 100%; box-sizing: border-box; height: 60px; border: 2px solid var(--border-color); border-radius: 12px; padding: 10px; font-size: 14px; resize: vertical; font-family: inherit; }
        #success-page { font-family: 'Noto Serif SC', serif; background: #1a2238; justify-content: center; align-items: center; text-align: center; color: white; position: relative; overflow: hidden; }
        .star { position: absolute; width: var(--star-size, 1px); height: var(--star-size, 1px); background: white; border-radius: 50%; animation: twinkle 5s infinite; filter: drop-shadow(0 0 2px white); }
        @keyframes twinkle { 0%, 100% { opacity: 0.3; } 50% { opacity: 1; } }
        .success-content { z-index: 1; font-family: 'Noto Serif SC', serif; }
        .success-title { font-size: 30px; font-weight: 700; text-shadow: 0 0 15px rgba(255, 255, 255, 0.6); animation: fadeInText 2s; }
        .success-subtitle { font-size: 15px; margin-top: 10px; opacity: 0.8; animation: fadeInText 2s 0.5s; font-weight: 400; }
        @keyframes fadeInText{ from{ opacity: 0; transform: translateY(20px); } to{ opacity: 1; transform: translateY(0); } }
    </style>
</head>
<body>
<div class="petpal-container" id="petpal-main-container">
    <div class="petpal-page active" id="login-page">
        <div class="login-panel">
            <div class="login-title-wrapper">
                <i class="fa-solid fa-paw login-title-icon"></i>
                <h2 class="login-title">Thẻ thông tin bạn đồng hành</h2>
                <i class="fa-solid fa-bone login-title-icon"></i>
            </div>
            <div class="login-form-group">
                <label class="login-form-label" for="setting-phase"><i class="fa-solid fa-leaf"></i>Giai đoạn gặp gỡ</label>
                <div class="petpal-select-wrapper"><select id="setting-phase" class="petpal-select" onchange="checkCustom(this)"><option value="🔮 准备相遇">🔮 Chuẩn bị gặp gỡ</option><option value="📦 静待开箱">📦 Chờ đợi mở hộp</option><option value="✨ 初来乍到">✨ Mới đến lần đầu</option><option value="🛋️ 渐渐习惯">🛋️ Dần dần quen thuộc</option><option value="❤️ 不可或缺">❤️ Không thể thiếu</option><option value="custom">📝 Tùy chỉnh...</option></select></div>
                <input type="text" id="setting-phase-custom" class="custom-input" placeholder="Vui lòng điền giai đoạn hiện tại của bạn">
            </div>
            <div class="login-form-group">
                <label class="login-form-label" for="setting-relationship"><i class="fa-solid fa-heart"></i>Mối quan hệ hiện tại</label>
                <div class="petpal-select-wrapper"><select id="setting-relationship" class="petpal-select" onchange="checkCustom(this)"><option value="⚔️ 互相敌视">⚔️ Thù địch lẫn nhau</option><option value="🧊 关系紧张">🧊 Quan hệ căng thẳng</option><option value="⚖️ 脆弱平衡">⚖️ Cân bằng mong manh</option><option value="🤝 平和相处">🤝 Chung sống hòa bình</option><option value="👑 完全认主">👑 Hoàn toàn nhận chủ</option><option value="💞 甜蜜亲热">💞 Ngọt ngào thân mật</option><option value="custom">📝 Tùy chỉnh...</option></select></div>
                <input type="text" id="setting-relationship-custom" class="custom-input" placeholder="Vui lòng điền mối quan hệ giữa bạn và họ">
            </div>
            <div class="login-form-group">
                <label class="login-form-label" for="setting-cognition"><i class="fa-solid fa-brain"></i>Tự nhận thức</label>
                <div class="petpal-select-wrapper"><select id="setting-cognition" class="petpal-select" onchange="checkCustom(this)">
                    <option value="🚫 决不接受">🚫 Tuyệt đối không chấp nhận</option>
                    <option value="💔 持续崩溃">💔 Suy sụp liên tục</option>
                    <option value="😵‍💫 认知失调">😵‍💫 Rối loạn nhận thức</option>
                    <option value="🧊 麻木被动">🧊 Tê liệt thụ động</option>
                    <option value="🌊 随波逐流">🌊 Thuận theo tự nhiên</option>
                    <option value="👍 基本适应">👍 Cơ bản thích ứng</option>
                    <option value="😊 完全接受">😊 Hoàn toàn chấp nhận</option>
                    <option value="custom">📝 Tùy chỉnh...</option>
                </select></div>
                 <input type="text" id="setting-cognition-custom" class="custom-input" placeholder="Vui lòng điền trạng thái nhận thức của búp bê">
            </div>
            <button class="petpal-button" style="margin-top: 15px;" onclick="goToOrderPage()">Bắt đầu tùy chỉnh</button>
        </div>
    </div>
    <div class="petpal-page" id="ordering-page">
        <header class="order-header">
            <h1 class="order-logo"><span class="logo-icon">👋</span> Pet&Pal Giao Hàng Tận Nhà</h1>
            <p class="order-subtitle">Chọn trải nghiệm đồng hành ưng ý, mở ra câu chuyện riêng của bạn và họ</p>
        </header>
        <div class="order-main">
            <aside class="order-sidebar" id="category-list"></aside>
            <main class="order-content" id="item-list"></main>
        </div>
        <div class="remark-section" id="remark-section">
             <textarea id="remark-input" placeholder="Có điều gì muốn nói với họ, hoặc thiết lập đặc biệt nào muốn bổ sung không? Bạn có thể viết tại đây nhé~"></textarea>
        </div>
        <footer class="order-footer">
            <div class="cart-info" onclick="toggleCartModal()">
                <div class="cart-icon fa-solid fa-cart-shopping" id="cart-icon">
                    <span class="cart-count" id="cart-count">0</span>
                </div>
                <div class="cart-summary">
                    <span class="cart-summary-text" id="cart-summary-text"></span>
                    <span class="cart-summary-placeholder" id="cart-summary-placeholder">Chưa chọn sản phẩm</span>
                </div>
            </div>
            <div class="order-actions">
                <a id="add-remark-btn" onclick="toggleRemark()">Thêm ghi chú</a>
                <button class="petpal-button" id="place-order-btn" onclick="placeOrder()">Đặt hàng ngay (Tùy chỉnh)</button>
            </div>
        </footer>
    </div>
    <div class="petpal-page" id="success-page"></div>
</div>
<div class="petpal-modal-overlay" id="confirm-modal">
    <div class="petpal-modal-box">
        <h3 class="petpal-modal-title">(=´ω`=) Nhắc nhở ấm áp</h3>
        <p class="petpal-modal-content">Để có trải nghiệm tốt nhất, vui lòng xác nhận bạn đã thêm thiết lập song sinh GT-X02 vào mô tả nhân vật hoặc World Book nhé～</p>
        <div class="petpal-modal-buttons">
            <button class="petpal-modal-button modal-button-secondary" onclick="closeModal('confirm-modal')">Tôi chưa thêm</button>
            <button class="petpal-modal-button modal-button-primary" onclick="confirmAndProceed()">Xác nhận, tiếp tục!</button>
        </div>
    </div>
</div>
<div class="petpal-modal-overlay" id="cart-modal">
    <div class="petpal-modal-box">
        <h3 class="petpal-modal-title">Giỏ hàng của tôi</h3>
        <div class="petpal-modal-content" id="cart-modal-content"><ul></ul></div>
        <div class="petpal-modal-buttons">
            <button class="petpal-modal-button modal-button-primary" onclick="closeModal('cart-modal')">Đóng</button>
        </div>
    </div>
</div>
<script>
    const pages = { login: document.getElementById('login-page'), ordering: document.getElementById('ordering-page'), success: document.getElementById('success-page') };
    const modals = { 'confirm-modal': document.getElementById('confirm-modal'), 'cart-modal': document.getElementById('cart-modal') };
    let userSelections = {}; let cart = [];
    const scenarios = [
        { category: '⚙️ Trải nghiệm cơ bản', items: [ { id: 'scn01', title: 'Khởi động lần đầu', desc: 'Kích hoạt búp bê độc quyền của bạn lần đầu, chứng kiến khoảnh khắc họ mở mắt.' }, { id: 'scn02', title: 'Tháo dỡ lần đầu', desc: '“Cái này cũng tháo được sao?” —— Thử tháo một bộ phận nào đó, quan sát phản ứng của họ.' }, { id: 'scn03', title: 'Trò chơi cộng cảm', desc: 'Điều chỉnh tỷ lệ đồng bộ cộng cảm, trải nghiệm kết nối kỳ diệu “nỗi đau của người là nỗi đau của tôi”.' }, { id: 'scn04', title: 'Cạn kiệt năng lượng', desc: 'Pin búp bê quá thấp, đã đến lúc cho họ trải nghiệm cảm giác sạc điện rồi.' }, { id: 'scn05', title: 'Ghi đè nhân cách', desc: 'Ghi nhân cách hoàn toàn mới cho họ, hôm nay họ sẽ là ai đây?' }, { id: 'scn06', title: 'Khám phá ranh giới', desc: 'Hôm nay búp bê cũng đang cố gắng chạy trốn? Hãy trải nghiệm chức năng tường không khí nhé.' } ] },
        { category: '🐾 Tương tác thú cưng', items: [ { id: 'scn07', title: 'Thử thách tìm về', desc: 'Ném món đồ chơi yêu thích cho búp bê dạng chó, xem cậu ấy có ngoan ngoãn ngậm về không.' }, { id: 'scn08', title: 'Đại chiến trốn tìm', desc: 'Búp bê dạng mèo lại trốn đi rồi, hãy tìm khắp nhà xem sao!' }, { id: 'scn09', title: 'Giấc mơ thú cưng', desc: 'Truyền ký ức động vật cho họ, họ sẽ mơ thấy thế giới như thế nào?' }, { id: 'scn10', title: 'Đại chiến chó mèo', desc: 'Khi bản năng của mèo và chó va chạm, sẽ là cảnh gà bay chó sủa thế nào?' } ] },
        { category: '🛋️ Chức năng nội thất', items: [ { id: 'scn11', title: 'Dịch vụ cà phê xay tươi', desc: 'Vào một buổi chiều nhàn nhã, thưởng thức cà phê nóng do búp bê mẫu B “pha chế”.' }, { id: 'scn12', title: 'Sạc dự phòng khẩn cấp', desc: 'Điện thoại của bạn hết pin rồi, may mà có họ bên cạnh.' }, { id: 'scn13', 'title': 'Máy khuếch tán hương thơm qua hơi thở', desc: 'Để hơi thở của họ tràn ngập mùi hương bạn thích, an ổn đi vào giấc ngủ.' } ] },
        { category: '☀️ Mảnh ghép thường ngày', items: [ { id: 'scn14', title: 'Đêm điện ảnh trên ghế sofa', desc: 'Cùng họ cuộn mình trong ghế sofa, trải qua một đêm được bao quanh bởi những chiếc đuôi lông xù.' }, { id: 'scn15', title: 'Cho ăn hôm nay', desc: 'Cho họ nếm thử một ít thức ăn của con người, xem họ có biểu cảm gì.' }, { id: 'scn16', title: 'Chào đón về nhà', desc: 'Kết thúc công việc một ngày trở về nhà, chào đón bạn là mèo con hay cún con?' } ] },
        { category: '🔞 Cảnh đặc biệt', items: [ { id: 'scn17', title: 'Playtime tháo dỡ', desc: 'Tháo các bộ phận cơ thể của họ xuống, tiến hành một số cách chơi táo bạo hơn.'}, { id: 'scn18', title: 'Thời gian hai người', desc: 'Tiến hành quan hệ tình dục thân mật, thông thường với một trong hai người.'}, { id: 'scn19', 'title': 'Tôi muốn tất cả', desc: 'Để cặp song sinh cùng hầu hạ bạn, tận hưởng niềm vui gấp đôi.'}, { id: 'scn20', title: 'Ủy thác đặc biệt', desc: 'Búp bê mẫu A bước vào kỳ phát tình, ủy quyền cho búp bê mẫu B đi an ủi cậu ấy.'} ] }
    ];
    function switchPage(pageName) { Object.values(pages).forEach(p => p.classList.remove('active')); if (pages[pageName]) pages[pageName].classList.add('active'); }
    function goToOrderPage() { modals['confirm-modal'].classList.add('active'); }
    function closeModal(modalName) { if (modals[modalName]) modals[modalName].classList.remove('active'); }
    function confirmAndProceed() {
        const phaseSelect = document.getElementById('setting-phase'); const relationshipSelect = document.getElementById('setting-relationship'); const cognitionSelect = document.getElementById('setting-cognition');
        userSelections.phase = phaseSelect.value === 'custom' ? document.getElementById('setting-phase-custom').value : phaseSelect.value;
        userSelections.relationship = relationshipSelect.value === 'custom' ? document.getElementById('setting-relationship-custom').value : relationshipSelect.value;
        userSelections.cognition = cognitionSelect.value === 'custom' ? document.getElementById('setting-cognition-custom').value : cognitionSelect.value;
        closeModal('confirm-modal'); switchPage('ordering'); initializeOrderingPage();
    }
    function checkCustom(selectElement) { const customInput = document.getElementById(selectElement.id + '-custom'); if (selectElement.value === 'custom') { customInput.style.display = 'block'; } else { customInput.style.display = 'none'; } }
    let isScrollingProgrammatically = false; let sectionOffsets = [];
    function initializeOrderingPage() { populateItems(); cacheSectionOffsets(); document.getElementById('item-list').addEventListener('scroll', handleContentScroll); }
    function populateItems() {
        const categoryList = document.getElementById('category-list'); const itemList = document.getElementById('item-list');
        categoryList.innerHTML = ''; itemList.innerHTML = '';
        scenarios.forEach((section, index) => {
            const categoryEl = document.createElement('div'); categoryEl.className = 'order-category' + (index === 0 ? ' active' : ''); categoryEl.textContent = section.category;
            categoryEl.dataset.target = 'section-' + index; categoryEl.onclick = () => scrollToCategory('section-' + index); categoryList.appendChild(categoryEl);
            const sectionEl = document.createElement('div'); sectionEl.className = 'content-section'; sectionEl.id = 'section-' + index;
            sectionEl.innerHTML = `<h3>${section.category}</h3>`;
            section.items.forEach(item => {
                const itemEl = document.createElement('div'); itemEl.className = 'item-card';
                itemEl.innerHTML = `<div class="item-info"><div class="item-title">${item.title}</div><div class="item-desc">${item.desc}</div></div><button class="add-to-cart-btn" id="btn-${item.id}" onclick="toggleCartItem(this, '${item.id}', '${item.title}', '${item.desc}')">+</button>`;
                sectionEl.appendChild(itemEl);
            });
            itemList.appendChild(sectionEl);
        });
    }
    function cacheSectionOffsets() { sectionOffsets = []; const itemList = document.getElementById('item-list'); document.querySelectorAll('.content-section').forEach(section => { sectionOffsets.push({ id: section.id, offset: section.offsetTop - itemList.offsetTop }); }); }
    function scrollToCategory(targetId) {
        isScrollingProgrammatically = true; const targetElement = document.getElementById(targetId);
        if (targetElement) { document.getElementById('item-list').scrollTo({ top: targetElement.offsetTop - 20, behavior: 'smooth' }); }
        document.querySelectorAll('.order-category').forEach(el => el.classList.remove('active')); document.querySelector(`.order-category[data-target="${targetId}"]`).classList.add('active');
        setTimeout(() => { isScrollingProgrammatically = false; }, 800);
    }
    function handleContentScroll(e) {
        if (isScrollingProgrammatically) return; const scrollPosition = e.target.scrollTop; let currentSectionId = sectionOffsets[0].id;
        for (let i = sectionOffsets.length - 1; i >= 0; i--) { if (scrollPosition >= sectionOffsets[i].offset - 25) { currentSectionId = sectionOffsets[i].id; break; } }
        document.querySelectorAll('.order-category').forEach(el => el.classList.remove('active'));
        const activeCategory = document.querySelector(`.order-category[data-target="${currentSectionId}"]`); if (activeCategory) { activeCategory.classList.add('active'); }
    }
    function toggleCartItem(button, id, title, desc) {
        const itemIndex = cart.findIndex(item => item.id === id);
        if (itemIndex > -1) { cart.splice(itemIndex, 1); button.classList.remove('added'); button.innerHTML = '+'; } else { cart.push({ id, title, desc }); button.classList.add('added'); button.innerHTML = ''; flyToCart(button); }
        updateCartView();
    }
    function flyToCart(button) { const rect = button.getBoundingClientRect();const cartIconRect = document.getElementById('cart-icon').getBoundingClientRect();const flyingItem = document.createElement('div');flyingItem.style.cssText = `position:fixed; left:${rect.left}px; top:${rect.top}px; width:20px; height:20px; background:var(--accent-pink); border-radius:50%; z-index:1001; transition:all 0.6s cubic-bezier(0.5, 0, 0.75, 0.04);`; document.body.appendChild(flyingItem); setTimeout(() => {flyingItem.style.left = cartIconRect.left + (cartIconRect.width / 2) - 10 + 'px';flyingItem.style.top = cartIconRect.top + (cartIconRect.height / 2) - 10 + 'px';flyingItem.style.transform = 'scale(0.1)';}, 10);setTimeout(() => {document.getElementById('cart-icon').classList.add('cart-icon-shake');document.body.removeChild(flyingItem);setTimeout(() => {document.getElementById('cart-icon').classList.remove('cart-icon-shake');}, 500);}, 600); }
    function removeCartItemFromModal(id) { const button = document.getElementById(`btn-${id}`); if(button) { toggleCartItem(button, id, '',''); } updateCartView(); updateCartModal(); }
