    <div id="package-page">
        <script>
            const packageContainerEl_v6_3 = document.getElementById('package-page');
            const confettiColors_v6_3 = ['#f48fb1', '#81d4fa', '#b39ddb', '#ffd54f', '#a5d6a7'];
            for (let i = 0; i < 50; i++) {
                const confetti = document.createElement('div');
                confetti.className = 'confetti';
                confetti.style.left = `${Math.random() * 100}%`;
                confetti.style.backgroundColor = confettiColors_v6_3[Math.floor(Math.random() * confettiColors_v6_3.length)];
                confetti.style.animationDelay = `${Math.random() * 7}s`;
                confetti.style.animationDuration = `${Math.random() * 4 + 5}s`;
                packageContainerEl_v6_3.appendChild(confetti);
            }
        </script>
        <h2>Surprise!</h2>
        <div class="package-image" onclick="triggerUnboxing()">🎁</div>
        <p class="delivery-text">Một món quà được tùy chỉnh dành riêng cho bạn đã được giao, vui lòng nhấp để ký nhận.</p>
    </div>
<script>
    let tipInterval;
    const dollTips = [
        "Khung xương của búp bê đã được xử lý nhẹ hóa, trọng lượng thấp hơn nhiều so với người bình thường cùng thể tích, thuận tiện hơn cho bạn di chuyển và bày biện tùy ý.",
        "Hệ thống cảm giác đau của búp bê có thể được khuếch đại, biến những cái chạm nhẹ nhất thành kích thích mãnh liệt, hãy đối xử dịu dàng nhé... hoặc là, không?",
        "'Mạng lưới cộng cảm' của chúng không thể bị tắt. Những gì làm với đứa này, đứa kia dù ở đâu cũng sẽ hoàn·toàn·cảm·nhận·được.",
        "Chương trình kỳ phát tình của búp bê mẫu A đang được hiệu chỉnh... dự kiến mỗi tháng sẽ có vài ngày trở nên đặc biệt quấn người, cần chủ nhân an ủi.",
        "Muốn chơi một trò chơi tìm đồ vui vẻ với búp bê mẫu B không?",
        "Dữ liệu nhân cách ban đầu của búp bê đã được sao lưu vĩnh viễn, bạn có thể biến chúng thành bất kỳ dáng vẻ nào bạn muốn bất cứ lúc nào, rồi lại khôi phục.",
        "Các mô-đun cơ thể của chúng đều sử dụng công nghệ tháo lắp nhanh bằng nam châm, nhưng chỉ có vân tay của bạn mới có thể ủy quyền tháo dỡ, chúng không tự động được đâu.",
        "Chúng sở hữu chức năng tự làm sạch hoàn hảo, bất kỳ dịch thể nào bạn bơm vào sẽ được hấp thụ hoàn toàn, chuyển hóa thành năng lượng phụ trợ."
    ];
    function updateDollTip() {
        const tipTextElement = document.getElementById('doll-tip-text');
        if (!tipTextElement) return;
        tipTextElement.style.opacity = '0';
        setTimeout(() => {
            const randomIndex = Math.floor(Math.random() * dollTips.length);
            tipTextElement.textContent = dollTips[randomIndex];
            tipTextElement.style.opacity = '1';
        }, 500);
    }
    function goToStep(step) {
        document.querySelector(`#page-container .page.active`)?.classList.remove('active');
        document.getElementById(`page-${step}`)?.classList.add('active');
        if (step === 5) {
            populateConfirmation();
        }
    }
    document.querySelectorAll('.custom-select').forEach(select => {
        select.addEventListener('change', e => {
            const customInput = e.target.nextElementSibling;
            if (customInput && (customInput.tagName === 'INPUT' || customInput.tagName === 'TEXTAREA')) {
                 customInput.style.display = e.target.value === 'Tùy chỉnh' ? 'block' : 'none';
            }
        });
    });
    document.querySelectorAll('.tag-grid').forEach(grid => {
        grid.addEventListener('click', e => {
            if (e.target.classList.contains('tag')) {
                e.target.classList.toggle(grid.id.includes('-a-') ? 'selected-A' : 'selected-B');
            }
        });
    });
    function getCustomValue(id) {
        const select = document.getElementById(id);
        if (!select) return '';
        return select.value === 'Tùy chỉnh' ? (select.nextElementSibling.value.trim() || 'Nội dung tùy chỉnh chưa được điền') : select.value;
    }
    function getTags(dollType) {
        const selected = Array.from(document.querySelectorAll(`#doll-${dollType}-tags .tag.selected-${dollType.toUpperCase()}`)).map(t => t.dataset.value);
        const custom = document.getElementById(`doll-${dollType}-tags-custom`).value.split(/,|，/).map(t => t.trim()).filter(Boolean);
        return [...new Set([...selected, ...custom])];
    }
    function createSummaryItem(label, value) {
        const cleanedValue = (typeof value === 'string') ? value.trim() : value;
        if (!cleanedValue || (Array.isArray(cleanedValue) && cleanedValue.length === 0)) return '';
        return `<div class="summary-item"><span class="label">${label}:</span><span class="value">${Array.isArray(cleanedValue) ? cleanedValue.join(', ') : cleanedValue}</span></div>`;
    }
    function populateConfirmation() {
        const data = collectFormData(false);
        document.getElementById('summary-a').innerHTML = [createSummaryItem('Tên', data.doll_A.name), createSummaryItem('Tuổi', data.doll_A.age), createSummaryItem('Giới tính', data.doll_A.gender), createSummaryItem('Nghề nghiệp', data.doll_A.occupation), createSummaryItem('Ngoại hình', data.doll_A.appearance), createSummaryItem('Kinh nghiệm tình dục', data.doll_A.sex_experience), createSummaryItem('Tính cách', data.doll_A.personality_tags)].join('');
        document.getElementById('summary-b').innerHTML = [createSummaryItem('Tên', data.doll_B.name), createSummaryItem('Tuổi', data.doll_B.age), createSummaryItem('Giới tính', data.doll_B.gender), createSummaryItem('Nghề nghiệp', data.doll_B.occupation), createSummaryItem('Ngoại hình', data.doll_B.appearance), createSummaryItem('Kinh nghiệm tình dục', data.doll_B.sex_experience), createSummaryItem('Tính cách', data.doll_B.personality_tags)].join('');
        document.getElementById('summary-backstory').innerHTML = [createSummaryItem('Nguồn gốc cơ thể', data.shared_backstory.modification_reason), createSummaryItem('Mối quan hệ nguyên thủy', data.shared_backstory.twin_relationship), createSummaryItem('Lý do sở hữu', data.shared_backstory.acquisition_method), createSummaryItem('Trạng thái mở hộp', data.shared_backstory.unboxing_state), createSummaryItem('Thiết lập bổ sung', data.shared_backstory.additional_settings)].join('');
    }

    function submitOrder() {
        // --- 新增功能：保存订单数据到世界书 ---
        const orderDataString = collectFormData(true);
        // !!! 用户须知: 请将下方的 "BespokeDolls设定" 和 uid=0 替换为您实际的世界书文件名和条目UID。
        const worldInfoFilename = "🐱Có cả chó lẫn mèo là một chuyện tốt đẹp biết bao🐶"; // 举例：您的世界书文件名为 "BespokeDolls设定.json"
        const worldInfoUID = 14;                     // 举例：您想保存在第1个条目中 (UID从0开始)
        const saveCommand = `/setentryfield file="${worldInfoFilename}" uid=${worldInfoUID} field=content ${escapeForSTScript(orderDataString)} || /echo severity=success Thông tin búp bê đã được lưuദ്ദി˶>ᴗo)✧`;

        if (typeof triggerSlash === 'function') {
            triggerSlash(saveCommand);
        } else {
            console.log("Chức năng Trợ lý quán rượu chưa được bật, không thể lưu vào World Book. Nội dung lệnh：", saveCommand);
        }
        // --- 新增功能结束 ---
        // 原有的代码继续执行，用于显示处理动画
        const orderForm = document.getElementById('order-form-container');
        const overlay = document.getElementById('processing-overlay');
        const steps = document.querySelectorAll('.progress-step');
        orderForm.style.display = 'none';
        overlay.classList.add('visible');
        let currentStep = 0;
        const interval = 2200;
        function processNextStep() {
            if (currentStep < steps.length) {
                steps[currentStep].classList.add('active');
                currentStep++;
                setTimeout(processNextStep, interval);
            } else {
                clearInterval(tipInterval);
                overlay.classList.remove('visible');
                document.getElementById('package-page').style.display = 'block';
            }
        }
        updateDollTip();
        tipInterval = setInterval(updateDollTip, 4000);
        processNextStep();
    }
    function triggerUnboxing() {
        const orderDataString = collectFormData(true);
        const orderData = JSON.parse(orderDataString);
        const prompt_message = `Bạn bây giờ hãy bắt đầu đóng vai một cảnh mở hộp. Dựa trên chi tiết đơn hàng tùy chỉnh dưới đây, hãy miêu tả {{user}} với tư cách là chủ nhân vừa nhận được một kiện hàng chuyển phát nhanh và đang chuẩn bị mở nó. Trong kiện hàng là hai búp bê dòng GT-X02 được đóng gói hoàn hảo, đang ở trạng thái “${orderData.shared_backstory.unboxing_state}”. Hãy miêu tả chi tiết quá trình mở hộp và trạng thái ban đầu của búp bê, và trong những tương tác tiếp theo, hãy diễn giải sinh động tính cách, mối quan hệ và bối cảnh của họ dựa trên tất cả các thiết lập của đơn hàng.\n\n【Chi tiết đơn hàng tùy chỉnh độc quyền】:\n${orderDataString}`;
        if (typeof triggerSlash === 'function') {
            document.getElementById('package-page').style.animation = 'shrinkOut 0.5s forwards';
            setTimeout(() => {
                triggerSlash(`/send ${escapeForSTScript(prompt_message)} | /trigger`);
            }, 500);
        } else {
            console.log("Generated Command:", `/send ${prompt_message} | /trigger`);
            alert("Chức năng Trợ lý quán rượu chưa được bật.");
        }
    }
    function collectFormData(asString = true) {
        const data = {
            doll_A: { name: document.getElementById('doll-a-name').value, age: document.getElementById('doll-a-age').value, gender: getCustomValue('doll-a-gender'), occupation: getCustomValue('doll-a-occupation'), appearance: getCustomValue('doll-a-appearance'), sex_experience: getCustomValue('doll-a-sex-experience'), personality_tags: getTags('a') },
            doll_B: { name: document.getElementById('doll-b-name').value, age: document.getElementById('doll-b-age').value, gender: getCustomValue('doll-b-gender'), occupation: getCustomValue('doll-b-occupation'), appearance: getCustomValue('doll-b-appearance'), sex_experience: getCustomValue('doll-b-sex-experience'), personality_tags: getTags('b') },
            shared_backstory: { modification_reason: getCustomValue('backstory-reason'), twin_relationship: getCustomValue('backstory-relationship'), acquisition_method: getCustomValue('backstory-acquisition'), unboxing_state: getCustomValue('backstory-unboxing-state'), additional_settings: document.getElementById('backstory-additional-settings').value }
        };
        // 移除空值字段，让JSON更整洁
        return asString ? JSON.stringify(data, (key, value) => (value === '' || (Array.isArray(value) && value.length === 0)) ? undefined : value, 2) : data;
    }
    document.head.insertAdjacentHTML("beforeend", `<style>@keyframes shrinkOut { to { transform: scale(0); opacity: 0; } }</style>`);
    function escapeForSTScript(str) { return typeof str === 'string' ? str.replace(/[|]/g, '\\$&') : str; }
</script>
