                            catch (e) { alert("Chuyển hướng thất bại: " + e); card.style.opacity = '1'; }
                        };
                        container.appendChild(card);
                    }
                }
                if (validCardsCount === 0) {
                     container.innerHTML = '<div style="padding:20px; text-align:center; opacity:0.6;">...Khu vực ký ức không có ghi chép hợp lệ...<br><small>Vui lòng đảm bảo các lời mở đầu khác có chứa chú thích title và desc</small></div>';
                }
            } catch (err) {
                console.error(err);
                container.innerHTML = `<div style="color:var(--c-accent)">CRITICAL ERROR: ${err.message}</div>`;
            }
        }
